const GATEWAY_URL = process.env.NEXT_PUBLIC_GATEWAY_URL ?? "http://localhost:8080";

export interface ChatRequest {
  message: string;
}

export interface ChatResponse {
  response: string;
}

// --- Structured run result (POST /api/v1/assess) â€” mirrors AssessResponse ---

export interface RunTrace {
  total_cost: number;
  lane: number; // 1 = rule-only Â· 2 = cheap Â· 3 = mortgage/veto
  replan_count: number;
  veto_fired: boolean;
}

export interface NodeTrace {
  node: string;
  model: string;
  tokens_in: number;
  tokens_out: number;
  cost: number;
  latency_ms: number;
  cache_hit: boolean;
  tool_calls: string[];
  schema_retries: number;
  fallback_fired: boolean;
}

export interface ComplianceVerdict {
  veto: boolean;
  rule_ids: string[];
  violations: unknown[];
  citations: unknown[];
}

export interface AssessResponse {
  response: string;
  outcome: string; // stp_approved | vetoed | ready_for_human_approval
  run_trace: RunTrace;
  compliance: ComplianceVerdict | null;
  trace: NodeTrace[];
  ticket: Record<string, unknown> | null;
  audit: Record<string, unknown> | null; // { record_id, seq, content_hash, prev_hash, decided_at } when AUDIT_SVC_URL set
}

// --- Service monitor (GET api-gateway /status) ---

export interface ServiceStatusItem {
  name: string;
  url: string;
  status: "up" | "down";
  latency_ms: number | null;
  critical: boolean;
  detail: Record<string, unknown>;
  error: string | null;
}

export interface ServiceStatusResponse {
  status: "ok" | "degraded";
  checked_at: string;
  summary: {
    total: number;
    up: number;
    down: number;
  };
